/**
 * EdJS Selects Module - OpenShop "Virtuozo" Edition
 * Optimized for the provided CSS animations.
 */
function Selects(options) {
    this.defaultOptions = {
        option: null,
        issearch: false,
        placeholder: _P('Select'),
        searchplaceholder: _P('search'),
        odabrano: _P('Selected'),
        ajaxUrl: '',
        data: { q: 'q' },
        ismultiselect: false,
        onSelect: null
    };
    this.config = Object.assign({}, this.defaultOptions, options || {});
    this.config.option = typeof this.config.option === 'string' ? document.querySelector(this.config.option) : this.config.option;
    this.isDropdownOpen = false;
    this.ids = this.config.option.getAttribute("id") || this.config.option.getAttribute("name") || 'sel-' + Math.floor(Math.random() * 1000);
    this.optionName = this.config.option.getAttribute("name");
    this.create();
}

Selects.prototype.create = function() {
    let opts = this.config.option.options;
    let css = this.config.option.getAttribute("style") || '';

    if (this.config.option.getAttribute("multiple") !== null) this.config.ismultiselect = true;

    if (!this.config.ismultiselect) {
        for (let i = 0; i < opts.length; i++) {
            if (opts[i].selected) this.config.placeholder = opts[i].textContent;
        }
    }

    let zindex = 99999 - document.querySelectorAll('.select-container').length;

    // STRUKTURA KOJU TVOJ CSS OČEKUJE
    let html = `<button type="button" role="combobox${this.ids}" aria-expanded="false">${this.config.placeholder}</button>
                <ul role="listbox${this.ids}">`;

    if (this.config.issearch) {
        html += `<li class="select-search-box">
                    <input type="text" class="select-search" placeholder="${this.config.searchplaceholder}">
                 </li>`;
    }

    for (let i = 0; i < opts.length; i++) {
        let activeClass = opts[i].selected ? 'active' : '';
        if (!this.config.ismultiselect) {
            html += `<li role="option${this.ids}" class="${activeClass}" data-value="${opts[i].value}">${opts[i].textContent}</li>`;
        } else {
            let checked = opts[i].selected ? 'checked="checked"' : '';
            html += `<li role="option${this.ids}" class="${activeClass}" data-value="${opts[i].value}">
                        <label><input type="checkbox" ${checked} name="${this.optionName}[]" value="${opts[i].value}" /> ${opts[i].textContent}</label>
                     </li>`;
        }
    }
    html += '</ul>';

    if (!this.config.ismultiselect) {
        html += `<div class="select-hidden-accessible">
                    <select id="${this.ids}" name="${this.optionName}">`;
        for (let i = 0; i < opts.length; i++) {
            let sel = opts[i].selected ? 'selected="selected"' : '';
            html += `<option value="${opts[i].value}" ${sel}>${opts[i].textContent}</option>`;
        }
        html += `</select></div>`;
    }

    let element = document.createElement('div');
    element.className = "select-container";
    element.innerHTML = html;
    element.style.cssText = css + (css.includes('z-index') ? '' : "z-index:" + zindex + ";");

    this.config.option.replaceWith(element);

    this.didoption = element.querySelector('select');
    this.config.button = element.querySelector('button');
    this.config.dropdown = element.querySelector('ul');
    this.options = element.querySelectorAll(`li[role="option${this.ids}"]`);
    if (this.config.issearch) this.config.search = element.querySelector('.select-search');

    this.bindEvents();
};

Selects.prototype.toggleDropdown = function() {
    this.isDropdownOpen = !this.isDropdownOpen;
    // CSS klasa 'active' pokreće transform: scale(1, 1)
    $(this.config.dropdown).toggleClass('active');
    this.config.button.setAttribute('aria-expanded', this.isDropdownOpen);
};

Selects.prototype.selectOption = function(li) {
    let val = li.getAttribute('data-value');
    let text = li.textContent;

    if (!this.config.ismultiselect) {
        this.didoption.value = val;
        this.config.button.textContent = text;
        this.options.forEach(el => el.classList.remove('active'));
        li.classList.add('active');
        this.toggleDropdown();
        if (this.config.onSelect) this.config.onSelect(val, text);
    } else {
        let chk = li.querySelector('input[type="checkbox"]');
        chk.checked = !chk.checked;
        li.classList.toggle('active', chk.checked);
        let count = Array.from(this.options).filter(el => el.querySelector('input').checked).length;
        this.config.button.textContent = `${this.config.odabrano} ${count}/${this.options.length}`;
    }
};

Selects.prototype.bindEvents = function() {
    $(this.config.button).on('click', (e) => {
        e.stopPropagation();
        this.toggleDropdown();
    });

    $(this.config.dropdown).on('click', 'li[role^="option"]', (e) => {
        this.selectOption(e.target.closest('li'));
    });

    if (this.config.issearch) {
        $(this.config.search).on('keyup', (e) => {
            let val = e.target.value.toLowerCase();
            this.options.forEach(el => {
                el.style.display = el.textContent.toLowerCase().includes(val) ? 'flex' : 'none';
            });
        });
        $(this.config.search).on('click', (e) => e.stopPropagation());
    }

    document.addEventListener('click', (e) => {
        if (!this.config.button.contains(e.target) && this.isDropdownOpen) this.toggleDropdown();
    });
};

(function($) {
    $.prototype.Selects = function(options) {
        return this.each(function() { new Selects(Object.assign({ option: this }, options)); });
    };
})(EdJS);
